+ '<td>' + escapeHtml(personUiText(personRelationship(row))) + '</td>'
+ '<td>' + formatDate(row.date_of_birth) + '</td>'
+ '<td>' + escapeHtml(ageText) + '</td>'
+ '<td>' + escapeHtml(personUiText(row.gender || '')) + '</td>'
+ '<td>' + escapeHtml(row.identity_number || '') + '</td>'
