async function saveHousehold(event) {
event.preventDefault();
const form = event.currentTarget;
const pendingId = form.elements.id?.value || '';
if (!requireUiPermission('household', pendingId ? 'update' : 'create')) return;
if (!form.checkValidity()) { form.classList.add('was-validated'); return; }
const payload = formData(form);
const id = payload.id; delete payload.id;
try {
await api(id ? `/api/households/${id}` : '/api/households', { method: id ? 'PUT' : 'POST', body: payload });
App.modals.household.hide(); showToast('Đã lưu hộ dân'); loadHouseholds(); loadDashboard(); refreshLoginConfig({ force: true });
} catch (error) { showToast(error.message, 'danger'); }
}
