function gisPolygonLatLngs(area) {
let geometry = area?.geometry ?? area?.polygon ?? area?.geometry_json ?? area?.geojson ?? [];
if (typeof geometry === 'string') { try { geometry = JSON.parse(geometry); } catch (error) { geometry = []; } }
if (geometry?.type === 'Feature') geometry = geometry.geometry || [];
if (geometry?.type === 'Polygon') geometry = geometry.coordinates?.[0] || [];
if (geometry?.type === 'MultiPolygon') geometry = geometry.coordinates?.[0]?.[0] || [];
const points = Array.isArray(geometry) && Array.isArray(geometry[0]) && Array.isArray(geometry[0][0]) ? geometry[0] : geometry;
return (Array.isArray(points) ? points : []).map(p => Array.isArray(p) ? [Number(p[1]), Number(p[0])] : [Number(p.lat ?? p.latitude), Number(p.lng ?? p.lon ?? p.longitude)]).filter(p => Number.isFinite(p[0]) && Number.isFinite(p[1]));
}
