function installGisManagers() {
App.gis.manager = {
map: {
init: initGisMap,
reload: loadGisMap,
switchBaseLayer: switchGisBaseLayer,
viewportKey: gisViewportKey,
boundsQuery: gisBoundsQuery
},
markers: {
loadViewport: loadGisViewportMarkers,
update: updateGisMarkers,
focus: focusGisHousehold
},
layers: {
renderAreas: renderGisAreas,
renderAreaList: renderGisAreaList,
focusArea: focusGisArea
},
popup: {
openHousehold: openGisHouseholdPopup,
renderHousehold: gisHouseholdDetailPopup
},
gps: {
start: startGisGps,
stop: stopGisGps
},
routing: {
householdDirectionsUrl: window.thon09GisDirectionsUrl || null
},
search: {
households: searchGisHouseholds
},
area: {
load: loadGisMap,
draw: startGisDraw,
save: saveGisArea,
cancel: cancelGisDraw,
redo: redoGisDraw,
undoPoint: undoGisDrawPoint,
edit: editGisArea,
delete: deleteGisArea
}
};
}
function initGisMap() {
gisDebugTrace('renderMap/initGisMap()');
gisWatchMapDom();
if (App.gis.map) { setTimeout(() => { gisDebugTrace('map.invalidateSize() existing map'); App.gis.map.invalidateSize(); }, 80); return; }
const map = L.map('gisMap', { zoomControl: true, preferCanvas: true, updateWhenIdle: true, updateWhenZooming: false, zoomSnap: 0.25, wheelDebounceTime: 80, maxZoom: 20 }).setView([20.2506, 105.9748], 14);
App.gis.map = map;
App.gis.tiles = gisTileLayers();
App.gis.baseLayer = App.gis.tiles.osm.addTo(map);
App.gis.layerGroup = L.featureGroup().addTo(map);
App.gis.markerCache = new Map();
App.gis.detailCache = new Map();
App.gis.viewportCache = new Map();
App.gis.loadedMarkerIds = new Set();
App.gis.openPopupId = '';
App.gis.popupInteractionUntil = 0;
App.gis.activeDrawHandler = null;
App.gis.editingArea = null;
App.gis.areaDirty = false;
App.gis.selectedArea = null;
App.gis.selectedAreaId = '';
App.gis.areaLayerMap = new Map();
installGisManagers();
App.gis.markerGroup = window.L.markerClusterGroup ? L.markerClusterGroup(gisMarkerClusterOptions(map)) : L.layerGroup();
App.gis.markerGroup.addTo(map);
if (L.Control.Draw) {
App.gis.drawControl = new L.Control.Draw({
draw: { polygon: { allowIntersection: false, showArea: true }, rectangle: false, circle: false, marker: false, circlemarker: false, polyline: false },
edit: { featureGroup: App.gis.layerGroup, remove: false }
});
map.addControl(App.gis.drawControl);
map.on(L.Draw.Event.CREATED, event => keepGisCreatedLayer(event.layer));
map.on(L.Draw.Event.EDITED, event => event.layers.eachLayer(layer => setGisDrawnLayer(layer)));
}
map.on('moveend zoomend', debounce(loadGisViewportMarkers, 180));
map.on('popupopen', () => { console.log('popupopen'); gisDebugTrace('popupopen'); });
map.on('popupclose', () => { console.trace('popupclose'); });
map.on('movestart', () => { console.trace('movestart'); });
map.on('moveend', () => { console.trace('moveend'); });
map.on('zoomstart', () => { console.trace('zoomstart'); });
map.on('zoomend', () => { console.trace('zoomend'); });
$('#gisDrawBtn')?.addEventListener('click', () => startGisDraw());
$('#gisUndoPointBtn')?.addEventListener('click', () => undoGisDrawPoint());
$('#gisRedoDrawBtn')?.addEventListener('click', () => redoGisDraw());
$('#gisCancelDrawBtn')?.addEventListener('click', () => cancelGisDraw());
$('#gisSaveBtn')?.addEventListener('click', () => saveGisArea());
$('#gisDeleteAreaBtn')?.addEventListener('click', () => { const id = $('#gisAreaId')?.value; if (id) deleteGisArea(id); });
bindGisDraftGuard();
$('#gisRefreshBtn')?.addEventListener('click', () => { if (!confirmDiscardGisDraft()) return; App.gis.viewportCache?.clear(); loadGisMap(); });
$('#gisPdfBtn')?.addEventListener('click', () => exportGisPdf());
$('#gisCurrentLocationBtn')?.addEventListener('click', () => startGisGps());
$('#gisBaseLayer')?.addEventListener('change', event => switchGisBaseLayer(event.target.value));
$('#gisSearch')?.addEventListener('input', debounce(() => { renderGisAreaList(App.gis.areas, $('#gisSearch').value); searchGisHouseholds(); loadGisViewportMarkers(true); }, 300));
document.addEventListener('click', event => { if (!event.target.closest('#gisSearchResults') && event.target.id !== 'gisSearch') $('#gisSearchResults')?.classList.add('d-none'); });
setTimeout(() => { gisDebugTrace('map.invalidateSize() initial map'); map.invalidateSize(); }, 200);
}
function switchGisBaseLayer(key) {
if (!App.gis.map || !App.gis.tiles?.[key]) return;
if (App.gis.baseLayer) App.gis.map.removeLayer(App.gis.baseLayer);
App.gis.baseLayer = App.gis.tiles[key].addTo(App.gis.map);
}
async function loadGisViewportMarkers(force = false) {
gisDebugTrace('loadMarkers/loadGisViewportMarkers()', { force });
const map = App.gis.map;
if (!map) return;
const shouldForce = force === true;
const search = $('#gisSearch')?.value.trim() || '';
if (!shouldForce && !search && gisHasOpenPopup()) return;
const key = gisViewportKey(map) + '|q=' + search.toLowerCase();
if (!shouldForce && App.gis.lastViewportKey === key) return;
App.gis.lastViewportKey = key;
const url = '/api/gis/households?light=1&' + gisBoundsQuery(map) + (search ? '&q=' + encodeURIComponent(search) : '');
const cached = !shouldForce ? App.gis.viewportCache?.get(key) : null;
gisDebugTrace('GET /api/gis/households viewport', { url, cached: Boolean(cached) });
const data = cached || await api(url, { cacheTtl: 20000 });
if (!cached) App.gis.viewportCache?.set(key, data);
updateGisMarkers(data.items || []);
updateGisMarkerSummary(data.summary || {}, data.items || []);
}
function updateGisMarkers(items) {
gisDebugTrace('updateMarkers/updateGisMarkers()', { itemCount: (items || []).length });
if (App.gis.openPopupId) return;
const nextIds = new Set(items.map(item => String(item.id)));
const nextMarkers = [];
items.forEach(item => {
const id = String(item.id);
const cached = App.gis.markerCache.get(id);
if (cached && Number(cached.data.latitude) === Number(item.latitude) && Number(cached.data.longitude) === Number(item.longitude)) {
cached.data = item;
nextMarkers.push(cached.marker);
return;
}
const marker = L.marker([Number(item.latitude), Number(item.longitude)], { title: item.household_code || item.head_citizen_name || 'H\u1ed9 gia \u0111\u00ecnh' });
const popup = L.popup({ closeButton: true, autoClose: true, closeOnClick: false, bubblingMouseEvents: false, autoPan: !gisIsTouchViewport(), keepInView: !gisIsTouchViewport() }).setContent(gisMarkerLoadingPopup(item));
marker.bindPopup(popup);
marker.on('click', () => { gisMarkPopupInteraction(id); gisDebugTrace('marker click -> openGisHouseholdPopup()', { id }); openGisHouseholdPopup(item.id, marker); });
['touchstart', 'touchend', 'pointerdown', 'pointerup'].forEach(type => marker.on(type, () => { gisMarkPopupInteraction(id); gisDebugTrace('marker ' + type, { id }); }));
marker.on('popupopen', () => {
console.log('popupopen');
gisMarkPopupInteraction(id);
App.gis.openPopupId = id;
protectGisPopup(marker.getPopup && marker.getPopup());
});
marker.on('popupclose', () => {
console.trace('popupclose');
if (App.gis.openPopupId === id && !gisInPopupInteractionWindow()) App.gis.openPopupId = '';
if (App.gis.selectedHouseholdId === id && !gisInPopupInteractionWindow()) App.gis.selectedHouseholdId = '';
});
App.gis.markerCache.set(id, { marker, data: item });
nextMarkers.push(marker);
});
Array.from(App.gis.markerCache.keys()).forEach(id => {
if (nextIds.has(id)) return;
App.gis.markerCache.delete(id);
});
gisDebugTrace('cluster.clearLayers()', { nextMarkerCount: nextMarkers.length });
App.gis.markerGroup.clearLayers();
if (typeof App.gis.markerGroup.addLayers === 'function') { gisDebugTrace('cluster.addLayers()', { nextMarkerCount: nextMarkers.length }); App.gis.markerGroup.addLayers(nextMarkers); }
else nextMarkers.forEach(marker => App.gis.markerGroup.addLayer(marker));
gisRefreshMarkerClusters();
}
function updateGisMarkerSummary(summary, items) {
const status = $('#gisMapStatus');
if (status) status.textContent = gisNumber(items.length) + ' marker trong v\u00f9ng nh\u00ecn - ' + gisNumber(summary.located || 0) + '/' + gisNumber(summary.households || 0) + ' h\u1ed9 \u0111\u00e3 \u0111\u1ecbnh v\u1ecb';
const host = $('#gisSummaryCards');
if (!host) return;
host.innerHTML = '<div><span>T\u1ed5ng h\u1ed9</span><b>' + gisNumber(summary.households || 0) + '</b></div>'
+ '<div><span>\u0110\u00e3 \u0111\u1ecbnh v\u1ecb</span><b>' + gisNumber(summary.located || 0) + '</b></div>'
+ '<div><span>Ch\u01b0a \u0111\u1ecbnh v\u1ecb</span><b>' + gisNumber(summary.unlocated || 0) + '</b></div>'
+ '<div><span>Trong v\u00f9ng nh\u00ecn</span><b>' + gisNumber(items.length) + '</b></div>';
}
function gisMarkerLoadingPopup(item) {
const row = item || {};
return '<div class="gis-household-popup gis-smart-popup"><div class="gis-smart-popup-head">'
+ '<div class="gis-smart-popup-photo">' + gisPopupPhotoHtml(row) + '</div>'
+ '<div><h4>' + gisEscape(row.household_code || 'H\u1ed9 gia \u0111\u00ecnh') + '</h4><p>' + gisEscape(row.head_citizen_name || '') + '</p><span>\u0110ang t\u1ea3i chi ti\u1ebft...</span></div></div></div>';
}
async function openGisHouseholdPopup(id, marker) {
gisMarkPopupInteraction(id);
gisDebugTrace('openGisHouseholdPopup()', { id: String(id) });
App.gis.selectedHouseholdId = String(id);
App.gis.openPopupId = String(id);
gisDebugTrace('marker.setPopupContent(loading)', { id: String(id) });
marker.setPopupContent(gisMarkerLoadingPopup(App.gis.markerCache.get(String(id))?.data || {}));
gisDebugTrace('marker.openPopup()', { id: String(id) });
marker.openPopup();
protectGisPopup(marker.getPopup && marker.getPopup());
setTimeout(() => hydrateAuthenticatedPreviews(marker.getPopup?.().getElement?.() || document), 0);
try {
gisDebugTrace('GET /api/gis/households/{id}/detail from popup click', { id: String(id), cached: App.gis.detailCache.has(String(id)) });
const detail = App.gis.detailCache.get(String(id)) || await api('/api/gis/households/' + encodeURIComponent(id) + '/detail', { cacheTtl: 30000 });
App.gis.detailCache.set(String(id), detail);
if (App.gis.selectedHouseholdId !== String(id) || (App.gis.openPopupId !== String(id) && !gisInPopupInteractionWindow())) return;
gisMarkPopupInteraction(id);
App.gis.openPopupId = String(id);
gisDebugTrace('marker.setPopupContent(detail)', { id: String(id) });
marker.setPopupContent(gisHouseholdDetailPopup(detail));
gisDebugTrace('marker.openPopup() after detail', { id: String(id) });
marker.openPopup();
protectGisPopup(marker.getPopup && marker.getPopup());
setTimeout(() => hydrateAuthenticatedPreviews(marker.getPopup?.().getElement?.() || document), 0);
} catch (error) {
if (App.gis.selectedHouseholdId !== String(id) || (App.gis.openPopupId !== String(id) && !gisInPopupInteractionWindow())) return;
gisMarkPopupInteraction(id);
gisDebugTrace('marker.setPopupContent(error)', { id: String(id), message: error.message || '' });
marker.setPopupContent('<div class="gis-household-popup gis-smart-popup"><strong>Kh\u00f4ng t\u1ea3i \u0111\u01b0\u1ee3c chi ti\u1ebft h\u1ed9</strong><p class="text-danger small">' + gisEscape(error.message || '') + '</p></div>');
gisDebugTrace('marker.openPopup() after error', { id: String(id) });
marker.openPopup();
}
}
function protectGisPopup(popup) {
if (!popup || typeof popup.getElement !== 'function') return;
const el = popup.getElement();
if (!el || el.__thon09GisPopupProtected) return;
el.__thon09GisPopupProtected = true;
el.style.pointerEvents = 'auto';
el.style.touchAction = 'manipulation';
if (window.L && L.DomEvent) {
L.DomEvent.disableClickPropagation(el);
L.DomEvent.disableScrollPropagation(el);
}
['touchstart', 'touchend', 'pointerdown', 'pointerup', 'click'].forEach(type => {
el.addEventListener(type, event => {
if (!event.target || !event.target.closest('.leaflet-popup-close-button')) event.stopPropagation();
}, { passive: false });
});
}
function gisHouseholdDetailPopup(detail) {
const h = detail.household || {};
const business = Array.isArray(detail.business) ? detail.business : [];
return '<div class="gis-household-popup gis-smart-popup">'
+ '<div class="gis-smart-popup-head"><div class="gis-smart-popup-photo">' + gisPopupPhotoHtml(h) + '</div>'
+ '<div><h4>' + gisEscape(h.household_code || 'H\u1ed9 gia \u0111\u00ecnh') + '</h4><p>' + gisEscape(h.head_citizen_name || 'Ch\u01b0a c\u00f3 ch\u1ee7 h\u1ed9') + '</p><span>' + gisEscape(gisHouseholdTypeText(h)) + '</span></div></div>'
+ '<dl>'
+ gisSmartPopupRow('M\u00e3 h\u1ed9', h.household_code)
+ gisSmartPopupRow('Ch\u1ee7 h\u1ed9', h.head_citizen_name)
+ gisSmartPopupRow('\u0110\u1ecba ch\u1ec9', h.address)
+ gisSmartPopupRow('S\u1ed1 nh\u00e2n kh\u1ea9u', gisNumber(h.total_members || 0))
+ gisSmartPopupRow('\u0110ang c\u01b0 tr\u00fa', gisNumber(h.at_home_count || 0))
+ gisSmartPopupRow('GPS', gisHouseholdGpsText(h))
+ gisSmartPopupBusinessRows(business)
+ '</dl>'
+ '<div class="gis-smart-popup-actions">'
+ gisHouseholdDetailButton(h)
+ gisDirectionsButton(h)
+ '</div>'
+ '</div>';
}
function gisPopupPhotoHtml(row) {
const fileId = Number(row?.thumbnail_file_id || row?.photo_file_id || row?.household_photo_file_id || 0);
if (fileId > 0) return '<img data-auth-preview="' + fileId + '" alt="\u1ea2nh h\u1ed9" loading="lazy">';
const url = row?.household_photo_url || row?.photo_url || row?.thumbnailUrl || '';
if (url && !/\/api\/files\/\d+\/preview/i.test(url)) return '<img src="' + gisEscape(url) + '" alt="\u1ea2nh h\u1ed9" loading="lazy">';
return '<div class="gis-household-popup-photo-empty"><i class="fa-solid fa-house-chimney"></i></div>';
}
function gisHouseholdTypeText(h) {
if (!h) return 'H\u1ed9 gia \u0111\u00ecnh';
if (h.household_type) return h.household_type;
if (h.business_name || h.business_marker_type) return 'H\u1ed9 c\u00f3 ho\u1ea1t \u0111\u1ed9ng kinh t\u1ebf';
return 'H\u1ed9 gia \u0111\u00ecnh';
}
function gisHouseholdGpsText(h) {
if (!h || !h.latitude || !h.longitude) return 'Ch\u01b0a c\u00f3 GPS';
const lat = Number(h.latitude);
const lng = Number(h.longitude);
if (!Number.isFinite(lat) || !Number.isFinite(lng)) return 'Ch\u01b0a c\u00f3 GPS';
return lat.toFixed(6) + ', ' + lng.toFixed(6) + (h.location_accuracy ? ' (' + gisNumber(h.location_accuracy) + ' m)' : '');
}
function gisSmartPopupRow(label, value) {
if (value === null || value === undefined || String(value).trim() === '') return '';
return '<dt>' + gisEscape(label) + '</dt><dd>' + gisEscape(value) + '</dd>';
}
function gisSmartPopupBusinessRows(items) {
if (!items.length) return '';
const rows = items.slice(0, 3).map(item => {
const title = item.business_name || item.economic_type || item.sector || 'Ho\u1ea1t \u0111\u1ed9ng kinh t\u1ebf';
const meta = [item.economic_type, item.sector].filter(Boolean).join(' - ');
return '<li><strong>' + gisEscape(title) + '</strong>' + (meta ? '<br><small>' + gisEscape(meta) + '</small>' : '') + '</li>';
}).join('');
const more = items.length > 3 ? '<li><small>Nh\u1ea5n Chi ti\u1ebft h\u1ed9 \u0111\u1ec3 xem to\u00e0n b\u1ed9</small></li>' : '';
return '<dt>Kinh doanh</dt><dd><ul class="mb-0 ps-3">' + rows + more + '</ul></dd>';
}
function gisHouseholdDetailButton(h) {
const id = Number(h?.id || 0);
if (!id) return '<button class="btn btn-sm btn-primary" type="button" onclick="switchScreen(\'households\')"><i class="fa-solid fa-folder-open"></i> Chi ti\u1ebft h\u1ed9</button>';
return '<button class="btn btn-sm btn-primary" type="button" onclick="showHousehold(' + id + ')"><i class="fa-solid fa-folder-open"></i> Chi ti\u1ebft h\u1ed9</button>';
}
function gisDirectionsButton(h) {
if (!h || !h.latitude || !h.longitude) return '';
const lat = Number(h.latitude);
const lng = Number(h.longitude);
if (!Number.isFinite(lat) || !Number.isFinite(lng)) return '';
const url = 'https://www.openstreetmap.org/directions?to=' + encodeURIComponent(lat + ',' + lng);
return '<a class="btn btn-sm btn-success" target="_blank" rel="noopener" href="' + gisEscape(url) + '"><i class="fa-solid fa-route"></i> Ch\u1ec9 \u0111\u01b0\u1eddng</a>';
}
