function gisRemoveDrawnLayer() { if (App.gis.drawnLayer && App.gis.layerGroup?.hasLayer(App.gis.drawnLayer)) App.gis.layerGroup.removeLayer(App.gis.drawnLayer); App.gis.drawnLayer = null; }
