if (canAccess('gis', 'update')) { showToast('Khu v\u1ef1c ch\u01b0a c\u00f3 ranh gi\u1edbi. B\u1ea1n c\u00f3 th\u1ec3 b\u1eaft \u0111\u1ea7u v\u1ebd.', 'info'); startGisDraw(false); }
