const GIS_GPS_TARGET_ACCURACY = 5;
const GIS_GPS_MAX_ACCEPTABLE_ACCURACY = 10;
const GIS_GPS_FALLBACK_AFTER_MS = 30000;
const GIS_GPS_TIMEOUT_MS = 60000;
async function startGisGps() {
if (!navigator.geolocation || !window.isSecureContext) return showToast('GPS chỉ hoạt động trên HTTPS hoặc localhost.', 'warning');
if (!App.gis.selectedHouseholdId) return showToast('Vui lòng mở marker hộ cần lưu GPS trước.', 'warning');
stopGisGps(false);
const panel = renderGisGpsPanel();
App.gis.gpsWatch = { panel, latest: null, best: null, marker: null, circle: null, watchId: null, startedAt: Date.now(), saving: false, timedOut: false, timeoutId: null };
updateGisGpsPanel('Đang lấy tín hiệu GPS...', 'Đang chờ...', true);
App.gis.gpsWatch.timeoutId = setTimeout(() => handleGisGpsTimeout(), GIS_GPS_TIMEOUT_MS);
App.gis.gpsWatch.watchId = navigator.geolocation.watchPosition(updateGisGps, handleGisGpsError, { enableHighAccuracy: true, timeout: GIS_GPS_TIMEOUT_MS, maximumAge: 0 });
}
function renderGisGpsPanel() {
const host = $('#gisMap')?.parentElement;
let panel = $('#gisGpsPanel');
if (!panel) { panel = document.createElement('div'); panel.id = 'gisGpsPanel'; panel.className = 'gis-gps-panel'; host?.appendChild(panel); }
panel.innerHTML = '<div class="d-flex justify-content-between gap-2"><strong>Định vị GPS</strong><button class="btn btn-sm btn-outline-secondary" type="button" data-gis-gps-close>Đóng</button></div><div class="gis-gps-grid"><span>Trạng thái</span><b data-gis-gps-status>Đang lấy tín hiệu GPS...</b><span>Sai số</span><b data-gis-gps-accuracy>Đang chờ...</b></div><div class="small text-muted" data-gis-gps-note>Không lưu vị trí nếu sai số trên 10 m.</div><div class="d-flex gap-2"><button class="btn btn-outline-success btn-sm" type="button" data-gis-gps-retry>Định vị lại</button></div>';
panel.querySelector('[data-gis-gps-close]').addEventListener('click', () => stopGisGps(true));
panel.querySelector('[data-gis-gps-retry]').addEventListener('click', startGisGps);
return panel;
}
function updateGisGpsPanel(status, accuracyText, working) {
const panel = App.gis.gpsWatch?.panel || $('#gisGpsPanel');
if (!panel) return;
const statusEl = panel.querySelector('[data-gis-gps-status]');
const accuracyEl = panel.querySelector('[data-gis-gps-accuracy]');
if (statusEl) statusEl.textContent = status;
if (accuracyEl) accuracyEl.textContent = accuracyText;
panel.classList.toggle('is-working', Boolean(working));
}
function updateGisGps(position) {
const watch = App.gis.gpsWatch;
if (!watch || watch.saving || watch.timedOut || !position?.coords || !App.gis.map) return;
const accuracy = Number(position.coords.accuracy || Infinity);
if (!Number.isFinite(accuracy)) return;
const latLng = [Number(position.coords.latitude), Number(position.coords.longitude)];
const sample = { latitude: latLng[0], longitude: latLng[1], accuracy };
watch.latest = sample;
if (!watch.best || accuracy < Number(watch.best.accuracy || Infinity)) watch.best = sample;
const best = watch.best;
const bestLatLng = [best.latitude, best.longitude];
if (!watch.marker) watch.marker = L.marker(bestLatLng, { title: 'Vị trí GPS tốt nhất' }).addTo(App.gis.map);
if (!watch.circle) watch.circle = L.circle(bestLatLng, { radius: best.accuracy || 10, color: '#2563eb', fillColor: '#2563eb', fillOpacity: .12, weight: 1 }).addTo(App.gis.map);
watch.marker.setLatLng(bestLatLng); watch.circle.setLatLng(bestLatLng); watch.circle.setRadius(best.accuracy || 10); App.gis.map.panTo(bestLatLng);
if (best.accuracy <= GIS_GPS_TARGET_ACCURACY) {
updateGisGpsPanel('GPS chính xác - đang lưu...', best.accuracy.toFixed(1) + ' m', true);
saveGisGpsForSelectedHousehold(best);
return;
}
const elapsed = Date.now() - watch.startedAt;
if (elapsed >= GIS_GPS_FALLBACK_AFTER_MS && best.accuracy <= GIS_GPS_MAX_ACCEPTABLE_ACCURACY) {
updateGisGpsPanel('Đủ chính xác - đang lưu...', best.accuracy.toFixed(1) + ' m', true);
saveGisGpsForSelectedHousehold(best);
return;
}
updateGisGpsPanel(best.accuracy <= GIS_GPS_MAX_ACCEPTABLE_ACCURACY ? 'Đang cải thiện...' : 'Đang lấy tín hiệu GPS...', best.accuracy.toFixed(1) + ' m', true);
}
function handleGisGpsError(error) {
const message = error?.message || 'Không lấy được GPS hiện tại';
updateGisGpsPanel('Không lấy được GPS', message, false);
showToast(message, 'warning');
}
function handleGisGpsTimeout() {
const watch = App.gis.gpsWatch;
if (!watch || watch.saving || watch.timedOut) return;
const best = watch.best;
if (best && best.accuracy <= GIS_GPS_MAX_ACCEPTABLE_ACCURACY) {
updateGisGpsPanel('Đủ chính xác - đang lưu...', best.accuracy.toFixed(1) + ' m', true);
saveGisGpsForSelectedHousehold(best);
return;
}
watch.timedOut = true;
if (watch.watchId != null) navigator.geolocation.clearWatch(watch.watchId);
updateGisGpsPanel('Không thể lấy GPS chính xác', best ? best.accuracy.toFixed(1) + ' m' : 'Không có tín hiệu', false);
showToast('Không thể lấy GPS chính xác. Vui lòng di chuyển ra nơi thoáng hoặc bật GPS chính xác cao rồi thử lại.', 'warning');
}
function stopGisGps(removePanel = true) {
const watch = App.gis.gpsWatch;
if (!watch) return;
if (watch.watchId != null) navigator.geolocation.clearWatch(watch.watchId);
if (watch.timeoutId) clearTimeout(watch.timeoutId);
watch.marker?.remove(); watch.circle?.remove();
if (removePanel) watch.panel?.remove();
App.gis.gpsWatch = null;
}
async function saveGisGpsForSelectedHousehold(sample) {
const watch = App.gis.gpsWatch;
const id = App.gis.selectedHouseholdId;
const gps = sample || watch?.best;
if (!watch || watch.saving) return;
if (!gps || !id) return showToast('Vui lòng mở marker hộ cần lưu GPS trước.', 'warning');
if (gps.accuracy > GIS_GPS_MAX_ACCEPTABLE_ACCURACY) return;
watch.saving = true;
if (watch.watchId != null) navigator.geolocation.clearWatch(watch.watchId);
if (watch.timeoutId) clearTimeout(watch.timeoutId);
try {
await api('/api/gis/households/' + encodeURIComponent(id) + '/location', { method: 'PUT', body: { latitude: gps.latitude, longitude: gps.longitude, source: 'GPS', accuracy: Math.round(gps.accuracy) } });
App.gis.viewportCache?.clear();
App.gis.detailCache?.delete(String(id));
const detail = await api('/api/gis/households/' + encodeURIComponent(id) + '/detail', { cacheTtl: 0 });
const saved = detail.household || {};
const savedLat = Number(saved.latitude);
const savedLng = Number(saved.longitude);
if (!Number.isFinite(savedLat) || !Number.isFinite(savedLng)) throw new Error('Dữ liệu GPS chưa được ghi vào database.');
const cached = App.gis.markerCache.get(String(id));
if (cached && cached.marker) {
cached.data = Object.assign({}, cached.data, saved);
cached.marker.setLatLng([savedLat, savedLng]);
cached.marker.setPopupContent(gisHouseholdDetailPopup(detail));
gisRefreshMarkerClusters();
} else {
await loadGisViewportMarkers(true);
}
const verified = App.gis.markerCache.get(String(id));
if (verified && verified.marker) {
const markerLatLng = verified.marker.getLatLng();
const markerLat = Number(markerLatLng.lat != null ? markerLatLng.lat : markerLatLng[0]);
const markerLng = Number(markerLatLng.lng != null ? markerLatLng.lng : markerLatLng[1]);
if (Math.abs(markerLat - savedLat) > 0.000001 || Math.abs(markerLng - savedLng) > 0.000001) throw new Error('Marker chưa cập nhật đúng vị trí vừa lưu.');
}
updateGisGpsPanel('GPS chính xác', Number(saved.location_accuracy || gps.accuracy).toFixed(1) + ' m', false);
showToast('Định vị thành công');
setTimeout(() => stopGisGps(true), 800);
} catch (error) {
watch.saving = false;
updateGisGpsPanel('Không lưu được GPS', gps.accuracy.toFixed(1) + ' m', false);
showToast(error.message || 'Không lưu được vị trí GPS.', 'danger');
}
}
window.loadGisMap = loadGisMap;
window.filterHouseholdsByGisArea = filterHouseholdsByGisArea;
window.focusGisArea = focusGisArea;
window.editGisArea = editGisArea;
window.deleteGisArea = deleteGisArea;
window.cancelGisDraw = cancelGisDraw;
window.redoGisDraw = redoGisDraw;
window.undoGisDrawPoint = undoGisDrawPoint;
window.exportGisPdf = exportGisPdf;
